import {Injectable, Logger} from "@nestjs/common"
import {ExecutionError, TransactionManager, TransactionOptions} from "@services"
import {Prisma} from "@prisma/client"
import {DatabaseClient, ConflictingIsolationLevelError} from "./database-client"

import {TaskEither} from "fp-ts/TaskEither"
import * as TE from "fp-ts/TaskEither"
import * as E from "fp-ts/Either"

class TransactionRollbackError<E> extends Error {
  constructor(public readonly errorPayload: E) {
    super("Transaction rolled back explicitly")
    this.name = "TransactionRollbackError"
  }
}

/**
 * Internal type guard for TransactionRollbackError.
 *
 * NOTE: While the generic type <E> is erased at runtime, this check is safe because
 * TransactionRollbackError is not exported and is only instantiated within this module's
 * `execute` method using the `E` of the provided computation.
 */
function isTransactionRollbackError<E extends string>(error: unknown): error is TransactionRollbackError<E> {
  return error instanceof TransactionRollbackError
}

@Injectable()
export class PrismaTransactionManager implements TransactionManager {
  constructor(private readonly dbClient: DatabaseClient) {}

  /**
   * @param computation - A function returning a `TaskEither` to be executed transactionally.
   * @param options - Optional configuration for the transaction.
   * @returns The result of the computation.
   */
  execute<T, E extends string>(
    computation: () => TaskEither<E, T>,
    options?: TransactionOptions
  ): TaskEither<E | ExecutionError, T> {
    return TE.tryCatch(
      async () => {
        return this.dbClient.transactional(
          async () => {
            const result = await computation()()
            if (E.isLeft(result))
              // Reject to rollback the transaction and propagate the error payload
              throw new TransactionRollbackError(result.left)
            else return result.right
          },
          {
            isolationLevel: options?.isolationLevel
              ? Prisma.TransactionIsolationLevel[options.isolationLevel]
              : undefined
          }
        )
      },
      (error: unknown) => {
        if (error instanceof ConflictingIsolationLevelError) {
          Logger.error("Conflicting isolation level requested.", error)
          return "conflicting_isolation_level" as const
        }

        if (isTransactionRollbackError<E>(error))
          // Extract the exact error payload generated by the computation TaskEither
          return error.errorPayload

        Logger.error("Unexpected error during transaction execution.", error)
        // If an unexpected error occurs during transaction creation or execution,
        // we return a left unknown error to be consistent with the rest of the code base
        return "unknown_error" as const
      }
    )
  }
}
